export const TREE_DOMAINS = ["Algebra", "Algebra and Graphs", "Calculus", "Coordinate Geometry", "Decision Mathematics", "Discrete Mathematics", "EDX-GCE", "EDX-IAL", "Functions", "Further Mechanics", "Further Pure Mathematics", "Further Statistics", "Geometry", "Legacy", "Matrix", "Mechanics", "Mensuration", "Number", "Probability", "Pure Mathematics", "Series", "Statistics", "Trigonometry", "Vectors", "Vectors and Transformations"];

/** Calculate overlap between any two subjects in real-time */
export function calculateOverlap(codeA: string, codeB: string): {
  comparison: {
    A: string; B: string;
    topicCountA: number; topicCountB: number;
  };
  summary: {
    symmetric: { unweighted: number; weighted: number };
    AtoB: { name: string; unweighted: { overlap: number; total: number; percentage: number }; weighted: { overlap: number; total: number; percentage: number } };
    BtoA: { name: string; unweighted: { overlap: number; total: number; percentage: number }; weighted: { overlap: number; total: number; percentage: number } };
  };
  sharedNodes: string[];
  aOnlyNodes: string[];
  bOnlyNodes: string[];
} | null {
  const subA = SUBJECT_LOOKUP[codeA];
  const subB = SUBJECT_LOOKUP[codeB];
  if (!subA || !subB) return null;

  const nodesA = subA.nodes;
  const nodesB = subB.nodes;
  const setA = new Set(Object.keys(nodesA));
  const setB = new Set(Object.keys(nodesB));
  const shared = [...setA].filter(x => setB.has(x));
  const union = new Set([...setA, ...setB]);

  const weight: Record<string, number> = { exact: 1.0, strong: 0.7, partial: 0.3, weak: 0.1 };
  let wInter = 0, wUnion = 0;
  let wAtoB = 0, wTotalA = 0, wBtoA = 0, wTotalB = 0;
  for (const nid of union) {
    const wA = weight[nodesA[nid] || 'partial'] || 0.3;
    const wB = weight[nodesB[nid] || 'partial'] || 0.3;
    wUnion += Math.max(wA, wB);
    if (nodesA[nid] && nodesB[nid]) {
      const minW = Math.min(wA, wB);
      wInter += minW;
      wAtoB += minW;
      wBtoA += minW;
    }
    if (nodesA[nid]) wTotalA += wA;
    if (nodesB[nid]) wTotalB += wB;
  }

  const aOnly = [...setA].filter(x => !setB.has(x));
  const bOnly = [...setB].filter(x => !setA.has(x));

  return {
    comparison: {
      A: subA.name,
      B: subB.name,
      topicCountA: Object.keys(nodesA).length,
      topicCountB: Object.keys(nodesB).length,
    },
    summary: {
      symmetric: {
        unweighted: union.size > 0 ? (shared.length / union.size) * 100 : 0,
        weighted: wUnion > 0 ? (wInter / wUnion) * 100 : 0,
      },
      AtoB: {
        name: `${codeA} → ${codeB}`,
        unweighted: { overlap: shared.length, total: setA.size, percentage: setA.size > 0 ? (shared.length / setA.size) * 100 : 0 },
        weighted: { overlap: wAtoB, total: wTotalA, percentage: wTotalA > 0 ? (wAtoB / wTotalA) * 100 : 0 },
      },
      BtoA: {
        name: `${codeB} → ${codeA}`,
        unweighted: { overlap: shared.length, total: setB.size, percentage: setB.size > 0 ? (shared.length / setB.size) * 100 : 0 },
        weighted: { overlap: wBtoA, total: wTotalB, percentage: wTotalB > 0 ? (wBtoA / wTotalB) * 100 : 0 },
      },
    },
    sharedNodes: shared,
    aOnlyNodes: aOnly,
    bOnlyNodes: bOnly,
  };
}
